head.script:
scwin.g_sUserId = "";
scwin.vAuthYn = "N";
scwin.stdYm = "";
scwin.strStdDt = "";

scwin.onpageload = async function() {
    scwin.g_sUserId = $c.ses.getUserId();
    scwin.strStdDt = WebSquare.date.getCurrentServerDate("yyyyMM");
    scwin.stdYm = $c.data.getParameter() != null ? ($c.data.getParameter()["stdYm"] || "") : "";

    ds_search.set("clsCd", "1");

    ica_stdYm.setValue(scwin.strStdDt);
    acb_crcCd.setValue("USD");

    scwin.f_getRamt();
    scwin.f_retrieveAuth();
    $c.gus.cfDisableObjects([ica_recvMagamDt, ica_paymentMagamDt]);

    if (scwin.stdYm.trim() != "") {
        ica_stdYm.setValue(scwin.stdYm);
        scwin.f_Retrieve();
        $c.gus.cfDisableObjects([btn_save, btn_saveAdditionalValue, btn_paymentDtsave]);
    }
};

scwin.f_retrieveAuth = async function() {
    // TODO: ds_auth 조회는 원본에서 DataId+Reset 방식(동적 쿼리)으로 처리됨. submission sbm_retrieveAuth로 대체 필요.
    await $c.sbm.execute(sbm_retrieveAuth);
};

scwin.sbm_retrieveAuth_submitdone = async function(e) {
    if (ds_auth.getRowCount() != 0) {
        $c.gus.cfEnableObjects([btn_paymentDtsave, btn_save, btn_saveAdditionalValue, acb_ramtCrcCd, ed_ramt]);
        scwin.vAuthYn = "Y";
    } else {
        $c.gus.cfDisableObjects([btn_paymentDtsave, btn_save, btn_saveAdditionalValue, acb_ramtCrcCd, ed_ramt]);
        scwin.vAuthYn = "N";
    }
};

scwin.sbm_retrieveAuth_submiterror = async function(e) {
    $c.gus.cfShowError(e);
};

scwin.getLastDayOfMonth = async function() {
    let year = ica_stdYm.getValue().substring(0, 4);
    let month = ica_stdYm.getValue().substring(4, 6);
    let date = new Date(year, month, 0);
    let lastDt = date.getDate();

    if (lastDt == 31) {
        gr_masterList.setColumnVisible("amt29d", true);
        gr_masterList.setColumnVisible("amt30d", true);
        gr_masterList.setColumnVisible("amt31d", true);
    } else if (lastDt == 30) {
        gr_masterList.setColumnVisible("amt29d", true);
        gr_masterList.setColumnVisible("amt30d", true);
        gr_masterList.setColumnVisible("amt31d", false);
    } else if (lastDt == 29) {
        gr_masterList.setColumnVisible("amt29d", true);
        gr_masterList.setColumnVisible("amt30d", false);
        gr_masterList.setColumnVisible("amt31d", false);
    } else if (lastDt == 28) {
        gr_masterList.setColumnVisible("amt29d", false);
        gr_masterList.setColumnVisible("amt30d", false);
        gr_masterList.setColumnVisible("amt31d", false);
    }
};

scwin.f_getRamt = async function() {
    // TODO: 원본은 동적 쿼리(dinymicQueryTest)로 TB_FM407 테이블을 직접 조회함. submission sbm_getRamt로 대체 필요. 서버 파라미터 구성 확인 필요.
    await $c.sbm.execute(sbm_getRamt);
};

scwin.sbm_getRamt_submitdone = async function(e) {
    if (ds_temp.getRowCount() != 0) {
        ds_fcrcRamt.set("stdYm", ds_temp.getCellData(0, "col1"));
        ds_fcrcRamt.set("crcCd", ds_temp.getCellData(0, "col2"));
        ds_fcrcRamt.set("ramt", ds_temp.getCellData(0, "col3"));
    } else {
        ds_fcrcRamt.set("ramt", 0);
    }
};

scwin.sbm_getRamt_submiterror = async function(e) {
    $c.gus.cfShowError(e);
};

scwin.f_openPopUp = async function(orgObjCd, orgObjNm, select_code, flag) {
    let rtnList = new Array();
    let cd = "";
    let nm = "";
    if (flag == "ALL") {
        cd = "";
        nm = "";
    } else {
        cd = orgObjCd.getValue();
        nm = orgObjNm.getValue();
    }

    switch (select_code) {
        case '1':
            break;
        case '2':
            rtnList = $c.gus.cfCommonPopUp('retrieveClntEmpNoList', cd, nm, "T", null, null, null, null, null, null, null, null, null);
            scwin.f_resultPopUp(orgObjCd, orgObjNm, rtnList);
            break;
        case '3':
            rtnList = $c.gus.cfCommonPopUp('retrieveAcEmpInfo', cd, nm, "T", null, null, null, null, null, null, null, null, null);
            scwin.f_resultPopUp(orgObjCd, orgObjNm, rtnList);
            break;
    }
};

scwin.f_CheckPopUp = async function(orgObjCd, orgObjNm, select_code, flag) {
    if (flag == "CD") {
        if (orgObjCd.getValue() == orgObjCd.hidVal) {
            return;
        } else {
            orgObjNm.setValue("");
        }
    } else {
        if (orgObjNm.getValue() == orgObjNm.hidVal) {
            return;
        } else {
            orgObjCd.setValue("");
        }
    }

    if (orgObjCd.getValue().trim() != "" || flag == "NM") {
        if (orgObjNm.getValue().trim() != "" || flag == "CD") {
            orgObjCd.setValue(orgObjCd.getValue().trim());
            orgObjNm.setValue(orgObjNm.getValue().trim());
            scwin.f_openPopUp(orgObjCd, orgObjNm, select_code, "NO");
        }
    } else {
        orgObjNm.setValue("");
        orgObjCd.setValue("");
        orgObjCd.hidVal = "";
    }
};

scwin.f_resultPopUp = async function(orgObjCd, orgObjNm, rtnList) {
    if (rtnList != null) {
        if (rtnList[0] == "N/A") {
            orgObjCd.setValue("");
            orgObjNm.setValue("");
            orgObjCd.hidVal = "";
            orgObjNm.hidVal = "";
            return;
        }
        orgObjCd.setValue(rtnList[0]);
        orgObjNm.setValue(rtnList[1]);
        orgObjCd.hidVal = rtnList[0];
        orgObjNm.hidVal = rtnList[1];
    } else {
        orgObjCd.setValue("");
        orgObjNm.setValue("");
        orgObjCd.hidVal = "";
        orgObjNm.hidVal = "";
    }
};

scwin.f_openCommonPopUp = async function(disGubun, pCode, pName, pClose, pAllSearch) {
    let rtnList;
    let row = ds_additionalValue.getRowPosition();

    switch (disGubun) {
        case 1:
            break;
        case 2:
            let param = ",,,000";
            pCode = ds_additionalValue.getCellData(row, "clntNo");
            rtnList = $c.gus.cfCommonPopUp('retrieveClntList', pCode, '', pClose, null, null, null, "3,4,5,6,7,8,9,10", param, null, null, null, null, null, null, null);
            if (rtnList != null) {
                if (rtnList[0] == "N/A") return false;
                ds_additionalValue.setCellData(row, "clntNo", rtnList[0]);
                ds_additionalValue.setCellData(row, "clntNm", rtnList[1]);
            }
            break;
    }
};

scwin.addComma = async function(number) {
    if (number == null || number === '' || isNaN(number)) number = 0;
    number = Number(number);
    return number.toLocaleString('ko-KR');
};

scwin.f_GridToExcel = async function(grObj, gridName) {
    if (ds_masterList.getRowCount() <= 0) {
        await $c.win.alert("내역이 존재하지않습니다.");
        return false;
    }
    $c.data.downloadGridViewExcel(grObj, {"fileName": gridName + ".xlsx", "sheetName": gridName});
};

scwin.f_Retrieve = async function() {
    let chk = await $c.gus.cfValidate([ica_stdYm]);
    if (!chk) return false;

    acb_ramtCrcCd.setValue(acb_crcCd.getValue());
    await scwin.f_getRamt();

    await scwin.f_getRecvMagam();
    await scwin.f_getPaymentMagam();

    if (ica_recvMagamDt.getValue() == "" || ica_paymentMagamDt.getValue() == "") {
        await $c.win.alert("계획 확정 전으로 조회가 불가합니다");
        return false;
    }

    await $c.sbm.execute(sbm_retrieve);
    await $c.sbm.execute(sbm_retrievePaymentDt);
    await $c.sbm.execute(sbm_retrieveAdditionalValue);
};

scwin.f_RetrievePaymentDt = async function() {
    let chk = await $c.gus.cfValidate([ica_stdYm]);
    if (!chk) return false;

    await $c.sbm.execute(sbm_retrievePaymentDt);
};

scwin.f_Save = async function() {
    if (ds_fcrcRamt.get("stdYm") == "" && ds_fcrcRamt.get("crcCd") == "" && ds_fcrcRamt.get("ramt") == "") {
        await $c.win.alert("데이타가 없습니다.");
        return;
    }

    if (ds_fcrcRamt.get("stdYm") == "") {
        ds_fcrcRamt.set("stdYm", ica_stdYm.getValue());
    }

    // TODO: DataMap isUpdated 체크 — 원본은 ds_fcrcRamt.isUpdated 사용. WebSquare DataMap에는 isUpdated가 없으므로 별도 처리 필요.
    await $c.sbm.execute(sbm_save);
};

scwin.f_AddPaymentDt = async function() {
    $c.data.insertRow(ds_paymentDt);
};

scwin.f_DeletePaymentDt = async function() {
    let row = ds_paymentDt.getRowPosition();
    if (row >= 0) {
        ds_paymentDt.removeRow(row);
    }
};

scwin.f_CancelPaymentDt = async function() {
    let row = ds_paymentDt.getRowPosition();
    if (row >= 0) {
        ds_paymentDt.undoRow(row);
    }
};

scwin.f_PaymentDtSave = async function() {
    let chk = await $c.gus.cfValidate([gr_paymentDt]);
    if (!chk) return false;

    if (ds_paymentDt.getRowCount() == 0) {
        await $c.win.alert("데이타가 없습니다.");
        return;
    }

    if (ds_paymentDt.getUpdatedIndex().length == 0) {
        await $c.win.alert("변경된 사항이 없습니다.");
        return;
    }

    for (let i = 0; i < ds_paymentDt.getRowCount(); i++) {
        let vStdDt = ds_paymentDt.getCellData(i, "paymentDt").substring(0, 6);
        if (vStdDt != ica_stdYm.getValue()) {
            await $c.win.alert((i + 1) + "행의 날짜는 기준년월의 월과 같아야 합니다.");
            return;
        }
    }

    await $c.sbm.execute(sbm_paymentDtSave);
};

scwin.f_Add = async function() {
    $c.data.insertRow(ds_additionalValue);
    let row = ds_additionalValue.getRowPosition();
    ds_additionalValue.setCellData(row, "crcCd", "USD");
    ds_additionalValue.setCellData(row, "clsCd", "1");
};

scwin.f_Delete = async function() {
    let row = ds_additionalValue.getRowPosition();
    if (row >= 0) {
        ds_additionalValue.removeRow(row);
    }
};

scwin.f_Cancel = async function() {
    let row = ds_additionalValue.getRowPosition();
    if (row >= 0) {
        ds_additionalValue.undoRow(row);
    }
};

scwin.f_SaveAdditionalValue = async function() {
    let chk = await $c.gus.cfValidate([gr_additionalValue]);
    if (!chk) return false;

    if (ds_additionalValue.getRowCount() == 0) {
        await $c.win.alert("데이타가 없습니다.");
        return;
    }

    if (ds_additionalValue.getUpdatedIndex().length == 0) {
        await $c.win.alert("변경된 사항이 없습니다.");
        return;
    }

    for (let i = 0; i < ds_additionalValue.getRowCount(); i++) {
        let vStdDt = ds_additionalValue.getCellData(i, "stdDt").substring(0, 6);
        if (vStdDt != ica_stdYm.getValue()) {
            await $c.win.alert((i + 1) + "행의 날짜는 기준년월의 월과 같아야 합니다.");
            return;
        }
        if (ds_additionalValue.getCellData(i, "additionalKndCd") == "") {
            await $c.win.alert((i + 1) + "행의 구분값을 입력하세요");
            return;
        }
    }

    await $c.sbm.execute(sbm_saveAdditionalValue);
};

scwin.f_getRecvMagam = async function() {
    // TODO: 원본은 동적 쿼리(dinymicQueryTest)로 TB_ZZ420, TB_ZZ419 테이블을 직접 조회함. submission sbm_getRecvMagam로 대체 필요. 서버 파라미터 구성 확인 필요.
    await $c.sbm.execute(sbm_getRecvMagam);
};

scwin.sbm_getRecvMagam_submitdone = async function(e) {
    if (ds_recvMagam.getRowCount() != 0) {
        ica_recvMagamDt.setValue(ds_recvMagam.getCellData(0, "col1"));
    } else {
        ica_recvMagamDt.setValue("");
    }
};

scwin.sbm_getRecvMagam_submiterror = async function(e) {
    $c.gus.cfShowError(e);
};

scwin.f_getPaymentMagam = async function() {
    // TODO: 원본은 동적 쿼리(dinymicQueryTest)로 TB_ZZ420, TB_ZZ419 테이블을 직접 조회함. submission sbm_getPaymentMagam로 대체 필요. 서버 파라미터 구성 확인 필요.
    await $c.sbm.execute(sbm_getPaymentMagam);
};

scwin.sbm_getPaymentMagam_submitdone = function(e) {
    if (ds_paymentMagam.getRowCount() != 0) {
        ica_paymentMagamDt.setValue(ds_paymentMagam.getCellData(0, "col1"));
    } else {
        ica_paymentMagamDt.setValue("");
    }
};

scwin.sbm_getPaymentMagam_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.f_addSum = function() {
    let vAmt1d = 0, vAmt2d = 0, vAmt3d = 0, vAmt4d = 0, vAmt5d = 0, vAmt6d = 0, vAmt7d = 0, vAmt8d = 0, vAmt9d = 0, vAmt10d = 0;
    let vAmt11d = 0, vAmt12d = 0, vAmt13d = 0, vAmt14d = 0, vAmt15d = 0, vAmt16d = 0, vAmt17d = 0, vAmt18d = 0, vAmt19d = 0, vAmt20d = 0;
    let vAmt21d = 0, vAmt22d = 0, vAmt23d = 0, vAmt24d = 0, vAmt25d = 0, vAmt26d = 0, vAmt27d = 0, vAmt28d = 0, vAmt29d = 0, vAmt30d = 0, vAmt31d = 0;
    let vSumAmt = 0;

    let vSumAmt1d = 0, vSumAmt2d = 0, vSumAmt3d = 0, vSumAmt4d = 0, vSumAmt5d = 0, vSumAmt6d = 0, vSumAmt7d = 0, vSumAmt8d = 0, vSumAmt9d = 0, vSumAmt10d = 0;
    let vSumAmt11d = 0, vSumAmt12d = 0, vSumAmt13d = 0, vSumAmt14d = 0, vSumAmt15d = 0, vSumAmt16d = 0, vSumAmt17d = 0, vSumAmt18d = 0, vSumAmt19d = 0, vSumAmt20d = 0;
    let vSumAmt21d = 0, vSumAmt22d = 0, vSumAmt23d = 0, vSumAmt24d = 0, vSumAmt25d = 0, vSumAmt26d = 0, vSumAmt27d = 0, vSumAmt28d = 0, vSumAmt29d = 0, vSumAmt30d = 0, vSumAmt31d = 0;
    let vTotSumAmt = 0;

    for (let i = 0; i < ds_masterList.getRowCount(); i++) {
        if (ds_masterList.getOriginalCellData(i, "additionalKndCd") == "1" && ds_masterList.getOriginalCellData(i, "clntNm") != "") {
            vAmt1d  = vAmt1d  + Number(ds_masterList.getOriginalCellData(i, "amt1d"));
            vAmt2d  = vAmt2d  + Number(ds_masterList.getOriginalCellData(i, "amt2d"));
            vAmt3d  = vAmt3d  + Number(ds_masterList.getOriginalCellData(i, "amt3d"));
            vAmt4d  = vAmt4d  + Number(ds_masterList.getOriginalCellData(i, "amt4d"));
            vAmt5d  = vAmt5d  + Number(ds_masterList.getOriginalCellData(i, "amt5d"));
            vAmt6d  = vAmt6d  + Number(ds_masterList.getOriginalCellData(i, "amt6d"));
            vAmt7d  = vAmt7d  + Number(ds_masterList.getOriginalCellData(i, "amt7d"));
            vAmt8d  = vAmt8d  + Number(ds_masterList.getOriginalCellData(i, "amt8d"));
            vAmt9d  = vAmt9d  + Number(ds_masterList.getOriginalCellData(i, "amt9d"));
            vAmt10d = vAmt10d + Number(ds_masterList.getOriginalCellData(i, "amt10d"));
            vAmt11d = vAmt11d + Number(ds_masterList.getOriginalCellData(i, "amt11d"));
            vAmt12d = vAmt12d + Number(ds_masterList.getOriginalCellData(i, "amt12d"));
            vAmt13d = vAmt13d + Number(ds_masterList.getOriginalCellData(i, "amt13d"));
            vAmt14d = vAmt14d + Number(ds_masterList.getOriginalCellData(i, "amt14d"));
            vAmt15d = vAmt15d + Number(ds_masterList.getOriginalCellData(i, "amt15d"));
            vAmt16d = vAmt16d + Number(ds_masterList.getOriginalCellData(i, "amt16d"));
            vAmt17d = vAmt17d + Number(ds_masterList.getOriginalCellData(i, "amt17d"));
            vAmt18d = vAmt18d + Number(ds_masterList.getOriginalCellData(i, "amt18d"));
            vAmt19d = vAmt19d + Number(ds_masterList.getOriginalCellData(i, "amt19d"));
            vAmt20d = vAmt20d + Number(ds_masterList.getOriginalCellData(i, "amt20d"));
            vAmt21d = vAmt21d + Number(ds_masterList.getOriginalCellData(i, "amt21d"));
            vAmt22d = vAmt22d + Number(ds_masterList.getOriginalCellData(i, "amt22d"));
            vAmt23d = vAmt23d + Number(ds_masterList.getOriginalCellData(i, "amt23d"));
            vAmt24d = vAmt24d + Number(ds_masterList.getOriginalCellData(i, "amt24d"));
            vAmt25d = vAmt25d + Number(ds_masterList.getOriginalCellData(i, "amt25d"));
            vAmt26d = vAmt26d + Number(ds_masterList.getOriginalCellData(i, "amt26d"));
            vAmt27d = vAmt27d + Number(ds_masterList.getOriginalCellData(i, "amt27d"));
            vAmt28d = vAmt28d + Number(ds_masterList.getOriginalCellData(i, "amt28d"));
            vAmt29d = vAmt29d + Number(ds_masterList.getOriginalCellData(i, "amt29d"));
            vAmt30d = vAmt30d + Number(ds_masterList.getOriginalCellData(i, "amt30d"));
            vAmt31d = vAmt31d + Number(ds_masterList.getOriginalCellData(i, "amt31d"));
            vSumAmt = vSumAmt + Number(ds_masterList.getOriginalCellData(i, "sumAmt"));
        } else if (ds_masterList.getOriginalCellData(i, "additionalKndCd") == "2" && ds_masterList.getOriginalCellData(i, "clntNm") != "") {
            vAmt1d  = vAmt1d  + (Number(ds_masterList.getOriginalCellData(i, "amt1d")) * -1);
            vAmt2d  = vAmt2d  + (Number(ds_masterList.getOriginalCellData(i, "amt2d")) * -1);
            vAmt3d  = vAmt3d  + (Number(ds_masterList.getOriginalCellData(i, "amt3d")) * -1);
            vAmt4d  = vAmt4d  + (Number(ds_masterList.getOriginalCellData(i, "amt4d")) * -1);
            vAmt5d  = vAmt5d  + (Number(ds_masterList.getOriginalCellData(i, "amt5d")) * -1);
            vAmt6d  = vAmt6d  + (Number(ds_masterList.getOriginalCellData(i, "amt6d")) * -1);
            vAmt7d  = vAmt7d  + (Number(ds_masterList.getOriginalCellData(i, "amt7d")) * -1);
            vAmt8d  = vAmt8d  + (Number(ds_masterList.getOriginalCellData(i, "amt8d")) * -1);
            vAmt9d  = vAmt9d  + (Number(ds_masterList.getOriginalCellData(i, "amt9d")) * -1);
            vAmt10d = vAmt10d + (Number(ds_masterList.getOriginalCellData(i, "amt10d")) * -1);
            vAmt11d = vAmt11d + (Number(ds_masterList.getOriginalCellData(i, "amt11d")) * -1);
            vAmt12d = vAmt12d + (Number(ds_masterList.getOriginalCellData(i, "amt12d")) * -1);
            vAmt13d = vAmt13d + (Number(ds_masterList.getOriginalCellData(i, "amt13d")) * -1);
            vAmt14d = vAmt14d + (Number(ds_masterList.getOriginalCellData(i, "amt14d")) * -1);
            vAmt15d = vAmt15d + (Number(ds_masterList.getOriginalCellData(i, "amt15d")) * -1);
            vAmt16d = vAmt16d + (Number(ds_masterList.getOriginalCellData(i, "amt16d")) * -1);
            vAmt17d = vAmt17d + (Number(ds_masterList.getOriginalCellData(i, "amt17d")) * -1);
            vAmt18d = vAmt18d + (Number(ds_masterList.getOriginalCellData(i, "amt18d")) * -1);
            vAmt19d = vAmt19d + (Number(ds_masterList.getOriginalCellData(i, "amt19d")) * -1);
            vAmt20d = vAmt20d + (Number(ds_masterList.getOriginalCellData(i, "amt20d")) * -1);
            vAmt21d = vAmt21d + (Number(ds_masterList.getOriginalCellData(i, "amt21d")) * -1);
            vAmt22d = vAmt22d + (Number(ds_masterList.getOriginalCellData(i, "amt22d")) * -1);
            vAmt23d = vAmt23d + (Number(ds_masterList.getOriginalCellData(i, "amt23d")) * -1);
            vAmt24d = vAmt24d + (Number(ds_masterList.getOriginalCellData(i, "amt24d")) * -1);
            vAmt25d = vAmt25d + (Number(ds_masterList.getOriginalCellData(i, "amt25d")) * -1);
            vAmt26d = vAmt26d + (Number(ds_masterList.getOriginalCellData(i, "amt26d")) * -1);
            vAmt27d = vAmt27d + (Number(ds_masterList.getOriginalCellData(i, "amt27d")) * -1);
            vAmt28d = vAmt28d + (Number(ds_masterList.getOriginalCellData(i, "amt28d")) * -1);
            vAmt29d = vAmt29d + (Number(ds_masterList.getOriginalCellData(i, "amt29d")) * -1);
            vAmt30d = vAmt30d + (Number(ds_masterList.getOriginalCellData(i, "amt30d")) * -1);
            vAmt31d = vAmt31d + (Number(ds_masterList.getOriginalCellData(i, "amt31d")) * -1);
            vSumAmt = vSumAmt + (Number(ds_masterList.getOriginalCellData(i, "sumAmt")) * -1);
        }
    }

    vSumAmt1d  = vAmt1d;
