scwin.sbm_retrieve_submitdone = async function(e) {
    scwin.getLastDayOfMonth();

    let rowcnt = ds_masterList.getRowCount();
    if (rowcnt == 0) {
        await $c.gus.cfAlertMsg(E_MSG_CM_WRN_002);
    }

    scwin.f_addSum();
};

